const rawUrl = $input.first().json.body.url;

if (!rawUrl) {
  throw new Error('No URL provided');
}

let cleanUrl = rawUrl.trim();
if (!cleanUrl.startsWith('http://') && !cleanUrl.startsWith('https://')) {
  cleanUrl = 'https://' + cleanUrl;
}

try {
  new URL(cleanUrl);
} catch (e) {
  throw new Error('Invalid URL format');
}

return [{ json: { url: cleanUrl } }];

const html = $input.first().json.body || $input.first().json.data || '';
const statusCode = $input.first().json.statusCode || 0;
const loadTime = $input.first().json.headers ? null : null;

function extractTag(regex, html) {
  const match = html.match(regex);
  return match ? match[1].trim() : null;
}

function extractAll(regex, html) {
  const results = [];
  let match;
  while ((match = regex.exec(html)) !== null) {
    results.push(match[1].replace(/<[^>]*>/g, '').trim());
  }
  return results;
}

const title = extractTag(/<title[^>]*>([^<]*)<\/title>/i, html);
const metaDescription = extractTag(/<meta\s+name=["']description["']\s+content=["']([^"']*)["']/i, html)
  || extractTag(/<meta\s+content=["']([^"']*)["']\s+name=["']description["']/i, html);

const h1s = extractAll(/<h1[^>]*>(.*?)<\/h1>/gis, html);
const h2s = extractAll(/<h2[^>]*>(.*?)<\/h2>/gis, html);
const h3s = extractAll(/<h3[^>]*>(.*?)<\/h3>/gis, html);

const hasViewportTag = /<meta\s+name=["']viewport["']/i.test(html);

const imgTags = html.match(/<img[^>]*>/gi) || [];
const imagesWithAlt = imgTags.filter(tag => /alt=["'][^"']+["']/.test(tag)).length;
const imagesTotal = imgTags.length;

const bodyText = html
  .replace(/<script[\s\S]*?<\/script>/gi, ' ')
  .replace(/<style[\s\S]*?<\/style>/gi, ' ')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const wordCount = bodyText.split(' ').filter(w => w.length > 0).length;

const hasSSL = $('Validate URL').first().json.url.startsWith('https://');

const metaSnippet = bodyText.slice(0, 2500);

return [{
  json: {
    url: $('Validate URL').first().json.url,
    statusCode,
    title,
    titleLength: title ? title.length : 0,
    metaDescription,
    metaDescriptionLength: metaDescription ? metaDescription.length : 0,
    h1s,
    h1Count: h1s.length,
    h2s: h2s.slice(0, 10),
    h3s: h3s.slice(0, 10),
    hasViewportTag,
    hasSSL,
    imagesTotal,
    imagesWithAlt,
    imageAltCoveragePercent: imagesTotal > 0 ? Math.round((imagesWithAlt / imagesTotal) * 100) : 100,
    wordCount,
    contentSnippet: metaSnippet
  }
}];

// Fallback path when fetch fails (site blocks bots, times out, etc.)
const urlNode = $('Validate URL').first().json.url;

return [{
  json: {
    url: urlNode,
    fetchFailed: true,
    error: 'Could not fetch this website. It may be blocking automated requests or temporarily unavailable.'
  }
}];

