const claudeResponse = $input.first().json;
const seoData = $('Extract SEO Data').first().json;

let reportText = claudeResponse.content[0].text;

reportText = reportText.trim();
if (reportText.startsWith('```')) {
  reportText = reportText.replace(/^```(json)?/, '').replace(/```$/, '').trim();
}

let report;
try {
  report = JSON.parse(reportText);
} catch (e) {
  throw new Error('Failed to parse AI response as JSON: ' + e.message);
}

return [{
  json: {
    success: true,
    url: seoData.url,
    crawledData: {
      title: seoData.title,
      metaDescription: seoData.metaDescription,
      h1Count: seoData.h1Count,
      wordCount: seoData.wordCount,
      hasSSL: seoData.hasSSL,
      hasViewportTag: seoData.hasViewportTag,
      imageAltCoveragePercent: seoData.imageAltCoveragePercent
    },
    report
  }
}];

return [{
  json: {
    success: false,
    url: $('Validate URL').first().json.url,
    error: $json.error || 'Something went wrong while generating your report. Please try again.'
  }
}];
